from adk import agent
class CircuitBreaker:
    def __init__(self):
        self.call_stack = []
        self.max_depth = 5

    def before_delegate(self, target_agent):
        self.call_stack.append(target_agent.name)
        if len(self.call_stack) > self.max_depth:
            raise ValueError('Max delegation depth exceeded')
        if self.call_stack[-2:] == self.call_stack[-4:-2]:
            raise ValueError('Circular delegation detected')

breaker = CircuitBreaker()
research_agent = agent('research')
research_agent.before_delegate_callback = breaker.before_delegate

from adk.sessions import Session
import copy

def create_immutable_session(base_session):
    class ImmutableSession:
        def __init__(self, state):
            self._state = state
            self._history = []

        def update(self, key, value):
            new_state = copy.deepcopy(self._state)
            new_state[key] = value
            self._history.append(new_state)
            return ImmutableSession(new_state)

        @property
        def state(self):
            return self._state

    return ImmutableSession(base_session.state)

conversation = Session()
immutable_conv = create_immutable_session(conversation)
